public static class EscalationRuleExcelColumnDefs
{
    public static readonly ExcelColumnDef Name = new("Name");
    public static readonly ExcelColumnDef Priority = new("Priority");
    public static readonly ExcelColumnDef ThresholdDays = new("Threshold Days");
    public static readonly ExcelColumnDef Tier = new("Tier");
    public static readonly ExcelColumnDef NotificationTarget = new("Notification Target");

    public static readonly ExcelColumnGroupDef PropertiesGroup = new(
        "Escalation Rule Properties",
        Name, Priority, ThresholdDays, Tier, NotificationTarget);

    public static IEnumerable<ExcelColumnDef> All
    {
        get
        {
            foreach (var col in PropertiesGroup.Columns)
                yield return col;
        }
    }
}

public class EscalationRuleExcelExporter(
    TranslationService translationService,
    ILogger<EscalationRuleExcelExporter> logger)
{
    public byte[] GenerateExcel(
        IList<EscalationRule> entities,
        Guid requestLanguageId,
        Guid defaultLanguageId)
    {
        var workbook = new ExcelFile();
        var worksheet = workbook.Worksheets.Add("Escalation Rules");

        // Header row
        var column = 0;
        foreach (var col in EscalationRuleExcelColumnDefs.All)
            worksheet.Cells[0, column++].Value = col.DisplayName;

        // Data rows
        for (var row = 0; row < entities.Count; row++)
        {
            var entity = entities[row];
            var name = translationService.GetEntityTranslation(
                entity.Translations, requestLanguageId, defaultLanguageId);

            column = 0;
            worksheet.Cells[row + 1, column++].Value = name?.Name ?? string.Empty;
            worksheet.Cells[row + 1, column++].Value = entity.Priority;
            worksheet.Cells[row + 1, column++].Value = entity.ThresholdDays;
            worksheet.Cells[row + 1, column++].Value = entity.Tier;
            worksheet.Cells[row + 1, column++].Value = entity.NotificationTarget;
        }

        using var stream = new MemoryStream();
        workbook.Save(stream, SaveOptions.XlsxDefault);
        return stream.ToArray();
    }
}

