public class EscalationRuleExcelImporter(
    EscalationRuleExcelImporterContextService contextService,
    ILogger<EscalationRuleExcelImporter> logger)
{
    public async Task<ExcelUploadResult<EscalationRuleDTO>> MapFromExcelFile(
        ExcelFile excelFile,
        Guid requestLanguageId,
        Guid defaultLanguageId,
        CancellationToken ct)
    {
        var result = new ExcelUploadResult<EscalationRuleDTO>();
        var context = await contextService.LoadAsync(ct);

        var worksheet = excelFile.Worksheets[0];
        if (worksheet.Rows.Count < 2)
        {
            result.UploadErrors.Add(new ExcelUploadError
            {
                RowIndex = 0, ColumnIndex = 0,
                ErrorMessage = "No data rows found"
            });
            return result;
        }

        // Build column index from header row
        var columnIndex = new Dictionary<string, int>();
        foreach (var col in EscalationRuleExcelColumnDefs.All)
        {
            var idx = FindColumnIndex(worksheet, col.DisplayName);
            if (idx >= 0)
                columnIndex[col.Key] = idx;
        }

        // Parse data rows
        for (var rowIdx = 1; rowIdx < worksheet.Rows.Count; rowIdx++)
        {
            var row = worksheet.Rows[rowIdx];
            var hasErrors = false;
            var dto = new EscalationRuleDTO { Id = Guid.Empty };

            // Required: Name
            var name = row.Cells.GetCellSafe(
                columnIndex.GetValueOrDefault("Name", -1))
                .GetStringValue();
            if (string.IsNullOrWhiteSpace(name))
            {
                result.UploadErrors.Add(new ExcelUploadError
                {
                    RowIndex = rowIdx, ColumnIndex = 0,
                    ErrorMessage = "Name is required"
                });
                hasErrors = true;
            }
            else
            {
                dto.Name = name;
            }

            // ... parse remaining columns ...

            if (!hasErrors)
                result.Items.Add(dto);
        }

        return result;
    }
}

