public class DownloadEscalationRuleExcelEndpoint(
    GetEscalationRulesQuery query,
    EscalationRuleExcelExporter exporter,
    ILogger<DownloadEscalationRuleExcelEndpoint> logger)
    : TenantEndpointWithoutRequest
{
    public override void Configure()
    {
        Post("/api/v1/admin/escalation-rules/download-excel");
        Description(x => x.WithName("DownloadEscalationRuleExcel"));
    }

    protected override async Task HandleValidatedRequestAsync(CancellationToken ct)
    {
        // 1. Load all entities for tenant
        var parameters = new EscalationRuleQueryParameters();
        var entities = await query.ExecuteAsync(parameters, ct);

        // 2. Generate Excel
        var bytes = exporter.GenerateExcel(
            entities, RequestLanguageId, DefaultLanguageId);

        // 3. Return file
        await SendBytesAsync(
            bytes,
            "escalation-rules.xlsx",
            "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
            cancellation: ct);
    }
}

public class UploadEscalationRuleExcelEndpoint(
    EscalationRuleExcelImporter importer,
    SaveEscalationRuleCommand saveCommand,
    ILogger<UploadEscalationRuleExcelEndpoint> logger)
    : TenantEndpoint<UploadEscalationRuleExcelRequest,
        UploadEscalationRuleExcelResponse>
{
    public override void Configure()
    {
        Post("/api/v1/admin/escalation-rules/upload-excel");
        AllowFileUploads();
        Description(x => x.WithName("UploadEscalationRuleExcel"));
    }

    protected override async Task HandleValidatedRequestAsync(
        UploadEscalationRuleExcelRequest req, CancellationToken ct)
    {
        // 1. Load Excel file
        await using var stream = req.File!.OpenReadStream();
        var excelFile = ExcelFile.Load(stream, LoadOptions.XlsxDefault);

        // 2. Parse rows into DTOs
        var importResult = await importer.MapFromExcelFile(
            excelFile, RequestLanguageId, DefaultLanguageId, ct);

        // 3. If parsing succeeded, save via batch command
        if (importResult.IsValid)
        {
            await saveCommand.ExecuteAsync(
                importResult.Items.ToList(),
                UserId, RequestLanguageId, DefaultLanguageId, ct);
        }

        // 4. Return result (items + errors)
        var response = new UploadEscalationRuleExcelResponse
        {
            Items = importResult.Items,
            UploadErrors = importResult.UploadErrors,
            UploadWarnings = importResult.UploadWarnings
        };

        await SendOkAsync(response, ct);
    }
}

