// Column definition
public record ExcelColumnDef(string DisplayName, string Key)
{
    public ExcelColumnDef(string displayName)
        : this(displayName, ToPascalCase(displayName)) { }
}

// Column group (for 2-level headers)
public record ExcelColumnGroupDef(
    string GroupName,
    IReadOnlyList<ExcelColumnDef> Columns)
{
    public ExcelColumnGroupDef(string groupName, params ExcelColumnDef[] columns)
        : this(groupName, columns.ToList()) { }
}

// Upload result
public class ExcelUploadResult<T>
{
    public List<T> Items { get; set; } = [];
    public List<ExcelUploadError> UploadErrors { get; set; } = [];
    public List<ExcelUploadWarning> UploadWarnings { get; set; } = [];
    public bool IsValid => UploadErrors.Count == 0;
}

// Error/Warning per cell
public class ExcelUploadError
{
    public int ColumnIndex { get; set; }
    public int RowIndex { get; set; }
    public string ErrorMessage { get; set; } = string.Empty;
}

public class ExcelUploadWarning
{
    public int ColumnIndex { get; set; }
    public int RowIndex { get; set; }
    public string WarningMessage { get; set; } = string.Empty;
}

